#!/usr/bin/perl
use strict;
use warnings;
use CAM::PDF;

# Function to extract date and author from the PDF
sub extract_info {
    my ($pdf) = @_;
    my $info = $pdf->getPageAsText(1);  # Get the first page as text
    $info =~ s/\r//g;  # Remove carriage returns
    $info =~ s/\n/ /g;  # Replace newlines with spaces

    # Extract date and author
    my ($date, $author);
    if ($info =~ /\/CreationDate\ (.*?)\ /) {
        $date = $1;
    }
    if ($info =~ /\/Author\ (.*?)\ /) {
        $author = $1;
    }
    return ($date, $author);
}

# Function to extract tables from the PDF
sub extract_tables {
    my ($pdf) = @_;
    my $content = $pdf->getPageContent(1);  # Get the content of the first page
    my @tables;
    # This is a simple regex to find tables. You may need to customize it based on your PDF format.
    if ($content =~ /Table\s+1:\s*(.*?)\s+Table\s+2:/s) {
        push @tables, $1;
    }
    if ($content =~ /Table\s+2:\s*(.*?)(?=Table\s+3|End of document)/s) {
        push @tables, $1;
    }
    return @tables;
}

